-- ---------------------------------------------------------- Tabel structuur voor tabel behand_klant-- --------------------------------------------------------DROP TABLE IF EXISTS behand_klant;CREATE TABLE behand_klant (relation_id int(11) NOT NULL auto_increment,behandelaar_id int(11) NOT NULL,persoon_id int(11) NOT NULL,beh_berichtontv smallint(3) default NULL,-- 0=nee 1=jaopdehoogte smallint(3) default NULL,beh_blokkeert smallint(3) default '0',databasis varchar(4) NOT NULL default 'nl',PRIMARY KEY (relation_id),KEY behandelaar_id (behandelaar_id),KEY persoon_id (persoon_id)) TYPE=MyISAM AUTO_INCREMENT=100 ;-- Gegevens worden uitgevoerd voor tabel behand_klantINSERT INTO `behand_klant` VALUES (99, 5, 5, 1, 1, 0, 'nl');